import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.BZO4qERu.js";const c=JSON.parse('{"title":"騎砍2 | 兵種大亂鬥：到底該帶什麼兵才不會被滅團？","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/troop-tier-list.md","filePath":"bannerlord/troop-tier-list.md"}'),o={name:"bannerlord/troop-tier-list.md"};function n(l,t,h,i,s,b){return r(),d("div",null,[...t[0]||(t[0]=[e(`<h1 id="騎砍2-兵種大亂鬥-到底該帶什麼兵才不會被滅團" tabindex="-1">騎砍2 | 兵種大亂鬥：到底該帶什麼兵才不會被滅團？ <a class="header-anchor" href="#騎砍2-兵種大亂鬥-到底該帶什麼兵才不會被滅團" aria-label="Permalink to &quot;騎砍2 | 兵種大亂鬥：到底該帶什麼兵才不會被滅團？&quot;">​</a></h1><hr><h2 id="前言-不是人數多就會贏" tabindex="-1">前言：不是人數多就會贏 <a class="header-anchor" href="#前言-不是人數多就會贏" aria-label="Permalink to &quot;前言：不是人數多就會贏&quot;">​</a></h2><p>很多新手有個迷思：<strong>兵越多越好</strong>。</p><p>然後帶著 100 個新兵被 50 個精銳騎兵輾過去，開始懷疑人生。</p><p>真相是：騎砍2的戰鬥，<strong>兵種搭配 &gt;&gt;&gt; 人海戰術</strong>。</p><p>50 個精銳士兵 &gt; 150 個新兵蛋子，這是鐵律。</p><hr><h2 id="一、兵種系統基礎" tabindex="-1">一、兵種系統基礎 <a class="header-anchor" href="#一、兵種系統基礎" aria-label="Permalink to &quot;一、兵種系統基礎&quot;">​</a></h2><p>每個國家的兵種樹大致分為三條路線：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新兵 → 步兵線 → 重步兵（前排扛線）</span></span>
<span class="line"><span>     → 射手線 → 弩手/弓手（後排輸出）</span></span>
<span class="line"><span>     → 騎兵線 → 重騎兵/弓騎兵（機動打擊）</span></span></code></pre></div><ul><li><strong>平民兵：</strong> 從村莊招募，可升級到 T5</li><li><strong>貴族兵：</strong> 從村莊的「權威人士」招募，可升級到 T6，屬性遠超平民兵</li></ul><hr><h2 id="二、六大文化兵種一句話總結" tabindex="-1">二、六大文化兵種一句話總結 <a class="header-anchor" href="#二、六大文化兵種一句話總結" aria-label="Permalink to &quot;二、六大文化兵種一句話總結&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文化</th><th>一句話評價</th></tr></thead><tbody><tr><td>🟦 <strong>帝國</strong></td><td>什麼都會，什麼都不特別強——最平衡的萬金油</td></tr><tr><td>🟩 <strong>巴坦尼亞</strong></td><td>弓兵強到靠北，但近戰跟紙糊的一樣</td></tr><tr><td>🟨 <strong>瓦蘭迪亞</strong></td><td>騎兵衝鋒很猛，弩兵陣地戰無敵</td></tr><tr><td>🟥 <strong>斯特吉亞</strong></td><td>步兵硬得像坦克，但跑得跟烏龜一樣</td></tr><tr><td>🟫 <strong>庫賽特</strong></td><td>騎射兵很煩（對敵人來說），公認後期最強文化</td></tr><tr><td>⬜ <strong>阿塞萊</strong></td><td>騎兵便宜好用，沙漠戰王者</td></tr></tbody></table><hr><h2 id="三、各文化王牌兵種" tabindex="-1">三、各文化王牌兵種 <a class="header-anchor" href="#三、各文化王牌兵種" aria-label="Permalink to &quot;三、各文化王牌兵種&quot;">​</a></h2><h3 id="s-級-版本答案-無腦出就對了" tabindex="-1">S 級：版本答案，無腦出就對了 <a class="header-anchor" href="#s-級-版本答案-無腦出就對了" aria-label="Permalink to &quot;S 級：版本答案，無腦出就對了&quot;">​</a></h3><table tabindex="0"><thead><tr><th>兵種</th><th>國家</th><th>類型</th><th>核心優勢</th></tr></thead><tbody><tr><td><strong>巴坦尼亞費奧納勇士</strong></td><td>巴坦尼亞</td><td>貴族弓手</td><td>遊戲最強遠程輸出，280 弓術、長弓射程最遠</td></tr><tr><td><strong>庫賽特可汗親衛</strong></td><td>庫賽特</td><td>貴族弓騎</td><td>騎射+近戰雙頂，風箏無敵</td></tr><tr><td><strong>帝國軍團步兵</strong></td><td>帝國</td><td>平民步兵</td><td>最全面的重步兵，能扛能打</td></tr></tbody></table><blockquote><p>📍 <strong>去哪招：</strong> 費奧納勇士 → 巴坦尼亞貴族村（<strong>Marunath、Seonon、Dunglanys</strong> 周圍村莊找「權威人士」）。可汗親衛 → 庫賽特貴族村（<strong>Makeb、Odokh</strong> 周邊）。帝國軍團步兵 → 任何帝國村莊升上去即可。</p></blockquote><h3 id="a-級-強勢選擇" tabindex="-1">A 級：強勢選擇 <a class="header-anchor" href="#a-級-強勢選擇" aria-label="Permalink to &quot;A 級：強勢選擇&quot;">​</a></h3><table tabindex="0"><thead><tr><th>兵種</th><th>國家</th><th>類型</th><th>備註</th></tr></thead><tbody><tr><td><strong>瓦蘭迪亞騎士</strong></td><td>瓦蘭迪亞</td><td>貴族騎兵</td><td>最強衝鋒騎兵</td></tr><tr><td><strong>帝國具裝騎兵</strong></td><td>帝國</td><td>平民騎兵</td><td>平民騎兵天花板</td></tr><tr><td><strong>瓦蘭迪亞弩手</strong></td><td>瓦蘭迪亞</td><td>平民弩手</td><td>弩傷害穩定，破甲能力強</td></tr><tr><td><strong>阿塞萊馬穆魯克騎兵</strong></td><td>阿塞萊</td><td>貴族騎兵</td><td>性價比最高</td></tr></tbody></table><h3 id="b-級-特定場合好用" tabindex="-1">B 級：特定場合好用 <a class="header-anchor" href="#b-級-特定場合好用" aria-label="Permalink to &quot;B 級：特定場合好用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>兵種</th><th>國家</th><th>備註</th></tr></thead><tbody><tr><td>斯特吉亞重裝斧兵</td><td>斯特吉亞</td><td>攻城/巷戰最強，但野戰機動太差</td></tr><tr><td>庫賽特重裝槍騎兵</td><td>庫賽特</td><td>平民騎兵中傷害最高</td></tr><tr><td>阿塞萊弓手</td><td>阿塞萊</td><td>弓箭+盾牌雙持、生存力強</td></tr></tbody></table><h3 id="c-級-不值得刻意練" tabindex="-1">C 級：不值得刻意練 <a class="header-anchor" href="#c-級-不值得刻意練" aria-label="Permalink to &quot;C 級：不值得刻意練&quot;">​</a></h3><table tabindex="0"><thead><tr><th>兵種</th><th>原因</th></tr></thead><tbody><tr><td>斯特吉亞獵人</td><td>當弓手不如巴坦尼亞，當步兵不如重裝斧兵</td></tr><tr><td>巴坦尼亞步兵線</td><td>裝備太差、被帝國步兵完爆</td></tr><tr><td>任何國家的 T1-T2 農民兵</td><td>純炮灰，後期直接解散</td></tr></tbody></table><hr><h2 id="四、三套黃金配兵方案" tabindex="-1">四、三套黃金配兵方案 <a class="header-anchor" href="#四、三套黃金配兵方案" aria-label="Permalink to &quot;四、三套黃金配兵方案&quot;">​</a></h2><h3 id="方案-1-野戰無敵流-庫賽特體系" tabindex="-1">方案 1：野戰無敵流（庫賽特體系） <a class="header-anchor" href="#方案-1-野戰無敵流-庫賽特體系" aria-label="Permalink to &quot;方案 1：野戰無敵流（庫賽特體系）&quot;">​</a></h3><p><strong>核心思路：</strong> 弓騎風箏消耗 → 騎兵側翼收割</p><table tabindex="0"><thead><tr><th>兵種</th><th style="text-align:center;">佔比</th><th>作用</th></tr></thead><tbody><tr><td>庫賽特可汗親衛</td><td style="text-align:center;">40%</td><td>開場散開自由射擊，風箏敵方主力</td></tr><tr><td>庫賽特重裝槍騎兵</td><td style="text-align:center;">30%</td><td>敵方陣型混亂後側翼衝鋒</td></tr><tr><td>帝國軍團步兵</td><td style="text-align:center;">30%</td><td>掩護弓騎，收尾用</td></tr></tbody></table><blockquote><p>⚠️ 弱點：攻城戰表現較弱，弓騎無法上城牆。</p></blockquote><h3 id="方案-2-萬金油均衡流-帝國體系" tabindex="-1">方案 2：萬金油均衡流（帝國體系） <a class="header-anchor" href="#方案-2-萬金油均衡流-帝國體系" aria-label="Permalink to &quot;方案 2：萬金油均衡流（帝國體系）&quot;">​</a></h3><p><strong>核心思路：</strong> 盾牆扛線 → 弓手輸出 → 騎兵收割 → 什麼情況都能打</p><table tabindex="0"><thead><tr><th>兵種</th><th style="text-align:center;">佔比</th><th>作用</th></tr></thead><tbody><tr><td>帝國軍團步兵</td><td style="text-align:center;">30%</td><td>前排盾牆扛住敵方衝鋒</td></tr><tr><td>巴坦尼亞費奧納勇士</td><td style="text-align:center;">35%</td><td>後排輸出主力</td></tr><tr><td>帝國具裝騎兵</td><td style="text-align:center;">25%</td><td>側翼保護+追擊</td></tr><tr><td>瓦蘭迪亞弩手</td><td style="text-align:center;">10%</td><td>破甲打重甲單位</td></tr></tbody></table><blockquote><p>✅ <strong>最推薦新手</strong>的配置。什麼情況都能應對，不需要微操。</p></blockquote><h3 id="方案-3-攻城特化流" tabindex="-1">方案 3：攻城特化流 <a class="header-anchor" href="#方案-3-攻城特化流" aria-label="Permalink to &quot;方案 3：攻城特化流&quot;">​</a></h3><table tabindex="0"><thead><tr><th>兵種</th><th style="text-align:center;">佔比</th><th>作用</th></tr></thead><tbody><tr><td>斯特吉亞重裝斧兵</td><td style="text-align:center;">40%</td><td>推攻城塔+破門+巷戰無敵</td></tr><tr><td>巴坦尼亞費奧納勇士</td><td style="text-align:center;">35%</td><td>在城下壓制城牆上的守軍</td></tr><tr><td>帝國軍團步兵</td><td style="text-align:center;">25%</td><td>扛箭塔、保護弓兵</td></tr></tbody></table><hr><h2 id="五、快速練兵技巧" tabindex="-1">五、快速練兵技巧 <a class="header-anchor" href="#五、快速練兵技巧" aria-label="Permalink to &quot;五、快速練兵技巧&quot;">​</a></h2><ol><li><strong>捐兵給軍團：</strong> 加入 AI 軍團，你的兵會自動分享軍團的戰鬥經驗</li><li><strong>打劫匪練 T1-T3：</strong> 初級兵打劫匪升級最快</li><li><strong>把要練的兵放在第一隊：</strong> 他們會優先分配到最多經驗</li><li><strong>點出領導力 perk：</strong> 全軍經驗加速</li></ol><hr><h2 id="六、基本戰鬥指揮懶人包" tabindex="-1">六、基本戰鬥指揮懶人包 <a class="header-anchor" href="#六、基本戰鬥指揮懶人包" aria-label="Permalink to &quot;六、基本戰鬥指揮懶人包&quot;">​</a></h2><p>不想學複雜戰術？記住這幾個指令就好：</p><ul><li><strong>F1 + F2</strong>：全軍跟我來</li><li><strong>F1 + F3</strong>：全軍衝鋒</li><li><strong>F2 + F3</strong>：步兵開盾牆</li><li><strong>F3 + F2</strong>：弓兵散開陣型</li></ul><h3 id="基本戰術流程" tabindex="-1">基本戰術流程： <a class="header-anchor" href="#基本戰術流程" aria-label="Permalink to &quot;基本戰術流程：&quot;">​</a></h3><ol><li>開戰 → 弓兵往高處站</li><li>步兵在弓兵前面開盾牆</li><li>騎兵到側面待命</li><li>等敵人接近 → 騎兵側面衝鋒</li><li>敵人潰散 → F1 + F3 全軍收割</li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li>還沒看過新手入門？→ <a href="./beginner-guide.html">騎砍2 | 新手求生指南</a></li><li>沒錢養兵？→ <a href="./money-making.html">騎砍2 | 賺錢密技</a></li><li>想自己建國？→ <a href="./kingdom-building.html">騎砍2 | 自立為王</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>`,55)])])}const u=a(o,[["render",n]]);export{c as __pageData,u as default};
